 10→/// Async-safe handle to the factory database.
 11→///
 12→/// Wraps `FactoryDb` behind `Arc<Mutex>` and runs all access on tokio's
 13→/// blocking thread pool via `spawn_blocking`, preventing synchronous SQLite
 14→/// I/O from tying up async worker threads.
 15→#[derive(Clone)]
 16→pub struct DbHandle {
 17→    inner: Arc<std::sync::Mutex<FactoryDb>>,
 18→}
 19→
 20→impl DbHandle {
 21→    pub fn new(db: FactoryDb) -> Self {
 22→        Self {
 23→            inner: Arc::new(std::sync::Mutex::new(db)),
 24→        }
 25→    }
 26→
 27→    /// Run a closure with access to the database on a blocking thread.
 28→    /// All data passed into `f` must be owned (`'static`).
 29→    pub async fn call<F, R>(&self, f: F) -> Result<R>
 30→    where
 31→        F: FnOnce(&FactoryDb) -> Result<R> + Send + 'static,
 32→        R: Send + 'static,
 33→    {
 34→        let db = self.inner.clone();
 35→        tokio::task::spawn_blocking(move || {
 36→            let guard = db
 37→                .lock()
 38→                .map_err(|e| anyhow::anyhow!("DB lock poisoned: {}", e))?;
 39→            f(&guard)
 40→        })
 41→        .await
 42→        .context("DB task panicked")?
 43→    }
 44→
 45→    /// Acquire the database mutex synchronously. Used in contexts where blocking
 46→    /// is acceptable: event batch flushing inside dedicated tasks, startup
 47→    /// initialization, and tests. Callers must ensure this is NOT called from
 48→    /// a hot async path to avoid blocking the tokio runtime.
 49→    pub fn lock_sync(&self) -> Result<std::sync::MutexGuard<'_, FactoryDb>> {
 50→        self.inner
 51→            .lock()
 52→            .map_err(|e| anyhow::anyhow!("DB lock poisoned: {}", e))
 53→    }
 54→}
