 54→/// Serve embedded static files or fall back to index.html for SPA routing.
 55→async fn static_handler(req: Request<Body>) -> impl IntoResponse {
 56→    let path = req.uri().path().trim_start_matches('/');
 57→
 58→    // Try to serve the exact file
 59→    if !path.is_empty()
 60→        && let Some(content) = Assets::get(path)
 61→    {
 62→        let mime = mime_guess::from_path(path).first_or_octet_stream();
 63→        match Response::builder()
 64→            .header(header::CONTENT_TYPE, mime.as_ref())
 65→            .body(Body::from(content.data.to_vec()))
 66→        {
 67→            Ok(resp) => return resp.into_response(),
 68→            Err(_) => return StatusCode::INTERNAL_SERVER_ERROR.into_response(),
 69→        }
 70→    }
 71→
 72→    // Fall back to index.html for SPA client-side routing
 73→    match Assets::get("index.html") {
 74→        Some(content) => Html(String::from_utf8_lossy(&content.data).to_string()).into_response(),
 75→        None => (
 76→            StatusCode::NOT_FOUND,
 77→            "Frontend not found. Run 'npm run build' in ui/ directory.",
 78→        )
 79→            .into_response(),
 80→    }
 81→}
