56→pub struct FactoryDb {
57→    conn: Connection,
58→}
59→
60→impl FactoryDb {
61→    /// Open (or create) a SQLite database at the given path and run migrations.
62→    pub fn new(path: &Path) -> Result<Self> {
63→        let conn = Connection::open(path).context("Failed to open SQLite database")?;
64→        let db = Self { conn };
65→        db.init()?;
66→        Ok(db)
67→    }
68→
69→    /// Create an in-memory SQLite database (for testing).
70→    pub fn new_in_memory() -> Result<Self> {
71→        let conn =
72→            Connection::open_in_memory().context("Failed to open in-memory SQLite database")?;
73→        let db = Self { conn };
74→        db.init()?;
75→        Ok(db)
76→    }
77→
78→    fn init(&self) -> Result<()> {
79→        self.conn
80→            .execute_batch("PRAGMA foreign_keys = ON;")
81→            .context("Failed to enable foreign keys")?;
82→        self.run_migrations().context("Failed to run migrations")?;
83→        Ok(())
84→    }
